    for i in 0..worker_count {
        let thread_rx = rx.clone();
        let thread_processed = Arc::clone(&processed_files);

        let worker = thread::spawn(move || {
            println!("Worker thread {} started", i);
            process_files(thread_rx, thread_processed);
        });

        workers.push(worker);
    }

    // Initial scan to organize existing files
    println!("Performing initial scan of directory");
    scan_directory(&watch_dir, &tx)?;

    // Start watching directory for changes
    println!("Starting file system watcher");
    watch_directory(&watch_dir, &tx)
}

fn num_cpus() -> usize {
    // Simple wrapper to get number of CPUs, defaulting to 4 if detection fails
    match thread::available_parallelism() {
        Ok(n) => n.get(),
        Err(_) => 4,
    }
}

fn process_files(rx: Receiver<PathBuf>, processed_files: Arc<Mutex<HashMap<PathBuf, SystemTime>>>) {
    while let Ok(file_path) = rx.recv() {
        if !file_path.is_file() {
            continue;
        }

        let should_process = {
            let mut processed = processed_files.lock().unwrap();

            // Check if file has already been processed with current modification time
            match fs::metadata(&file_path) {
                Ok(metadata) => {
                    match metadata.modified() {
                        Ok(modified) => {
                            if let Some(last_processed) = processed.get(&file_path) {
                                if *last_processed >= modified {
                                    false // Skip if already processed this version
                                } else {
                                    // Update processed state
                                    processed.insert(file_path.clone(), modified);
                                    true
                                }
                            } else {
                                // First time seeing this file
                                processed.insert(file_path.clone(), modified);
                                true
                            }
                        },
                        Err(_) => false, // Can't get modified time, skip
                    }
                },
                Err(_) => false, // Can't get metadata, skip
            }
        };

        if should_process {
            organize_file(&file_path);
        }
    }
}

fn scan_directory(dir: &Path, tx: &Sender<PathBuf>) -> std::io::Result<()> {
    for entry in fs::read_dir(dir)? {
        let entry = entry?;
        let path = entry.path();

        if path.is_file() {
            let _ = tx.send(path);
        }
    }

    Ok(())
}

fn watch_directory(dir: &Path, tx: &Sender<PathBuf>) -> std::io::Result<()> {
    let watcher_dir = dir.to_path_buf();
    let watcher_tx = tx.clone();

    // Since Rust 1.74.0 doesn't have built-in file watching API in std,
    // we implement a polling-based approach
    let mut last_scan = SystemTime::now();
    let poll_interval = Duration::from_millis(500);

    println!("Watching directory {} (polling every {:?})", watcher_dir.display(), poll_interval);

    loop {
        thread::sleep(poll_interval);

        if let Err(e) = scan_and_detect_changes(&watcher_dir, &watcher_tx, &mut last_scan) {
            eprintln!("Error scanning directory: {}", e);
        }
    }
}

fn scan_and_detect_changes(
    dir: &Path,
    tx: &Sender<PathBuf>,
    last_scan: &mut SystemTime
) -> std::io::Result<()> {
    let current_time = SystemTime::now();

    for entry in fs::read_dir(dir)? {
        let entry = entry?;
        let path = entry.path();

        if !path.is_file() {
            continue;
        }

        let metadata = entry.metadata()?;
        if let Ok(modified) = metadata.modified() {
            // Check if file was modified since last scan
            if modified >= *last_scan {
                let _ = tx.send(path);
            }
        }
    }

    *last_scan = current_time;
    Ok(())
}

fn organize_file(file_path: &Path) {
    if let Some(extension) = file_path.extension() {
        let ext_str = extension.to_string_lossy().to_lowercase();

        if let Some(parent_dir) = file_path.parent() {
            let target_dir = parent_dir.join(&ext_str);

            // Create extension directory if it doesn't exist
            if !target_dir.exists() {
                if let Err(e) = fs::create_dir_all(&target_dir) {
                    eprintln!("Failed to create directory for extension {}: {}", ext_str, e);
                    return;
                }
                println!("Created directory for extension: {}", target_dir.display());
            }

            if let Some(file_name) = file_path.file_name() {
                let target_path = target_dir.join(file_name);

                // Handle case where target file already exists
                if target_path.exists() {
                    // Generate a unique name by appending a timestamp
                    if let Ok(now) = SystemTime::now().duration_since(SystemTime::UNIX_EPOCH) {
                        let unique_name = format!(
                            "{}_{}.{}",
                            file_path.file_stem().unwrap().to_string_lossy(),
                            now.as_secs(),
                            ext_str
                        );
                        let unique_target = target_dir.join(unique_name);

                        // Move the file with unique name
                        match fs::rename(file_path, &unique_target) {
                            Ok(_) => println!("Moved {:?} to {:?} (renamed to avoid conflict)", file_path, unique_target),
                            Err(e) => eprintln!("Failed to move {:?}: {}", file_path, e),
                        }
                    } else {
                        eprintln!("Failed to generate unique name for {:?}", file_path);
                    }
                } else {
                    // Move the file (normal case)
                    match fs::rename(file_path, &target_path) {
                        Ok(_) => println!("Moved {:?} to {:?}", file_path, target_path),
                        Err(e) => eprintln!("Failed to move {:?}: {}", file_path, e),
                    }
                }
            }
        }
    }
}
