        }
    }

    private void executeRetentionPolicies() {
        logger.info("Executing retention policies - {} policies found", retentionPolicies.size());

        retentionPolicies.forEach((key, policy) -> {
            String[] parts = key.split(":");
            String tableName = parts[0];
            DatabaseType dbType = DatabaseType.valueOf(parts[1]);

            try {
                long startTime = System.currentTimeMillis();
                int count = switch (dbType) {
                    case SQL -> executeSqlRetentionPolicy(tableName, policy);
                    case MONGODB -> executeMongoDbRetentionPolicy(tableName, policy);
                    case CASSANDRA, DYNAMODB -> {
                        logger.warn("{} support not implemented yet", dbType);
                        yield 0;
                    }
                };
                long elapsedTime = System.currentTimeMillis() - startTime;

                logger.info("Executed retention policy for {} ({}) - {} records purged in {}ms", 
