            LocalDateTime cutoffDate = LocalDateTime.now().minus(policy.duration(), policy.unit());

            String dateField = policy.dateField();
            Object cutoffValue = switch (policy.dateFieldType()) {
                case TIMESTAMP, DATE -> java.util.Date.from(cutoffDate.toInstant(ZoneOffset.UTC));
                case EPOCH -> cutoffDate.toEpochSecond(ZoneOffset.UTC);
                case ISO_STRING -> cutoffDate.toString();
            };

            Document filter = new Document(dateField, new Document("$lt", cutoffValue));
            var result = database.getCollection(collectionName).deleteMany(filter);
            return (int) result.getDeletedCount();
        }
    }

