use std::collections::VecDeque;
use std::error::Error;
use std::io::{self, BufRead};

struct StockEntry {
    symbol: String,
    timestamp: String,
    price: f64,
}

struct MovingAverageResult {
    symbol: String,
    timestamp: String,
    price: f64,
    moving_avg: f64,
}

fn main() -> Result<(), Box<dyn Error>> {
    let stdin = io::stdin();
    let reader = stdin.lock();

    let mut lines = reader.lines();
    // Skip header line
    if let Some(Ok(_)) = lines.next() {}

    let mut history: VecDeque<StockEntry> = VecDeque::with_capacity(10);

    for line_result in lines {
        match line_result {
            Ok(line) => {
                match parse_csv_line(&line) {
                    Ok(entry) => {
                        // Add new entry to history
                        history.push_back(entry);

                        // Keep only the last 10 entries
                        if history.len() > 10 {
                            history.pop_front();
                        }

                        // Calculate moving average
                        let avg = calculate_moving_average(&history);

                        // Get the latest entry
                        if let Some(latest) = history.back() {
                            let result = MovingAverageResult {
                                symbol: latest.symbol.clone(),
                                timestamp: latest.timestamp.clone(),
                                price: latest.price,
                                moving_avg: avg,
                            };

                            // Output the result
                            println!("{},{},{:.2},{:.2}", 
                                result.symbol, 
                                result.timestamp, 
                                result.price, 
                                result.moving_avg
                            );
                        }
                    },
                    Err(e) => {
                        eprintln!("Error parsing CSV line: {}", e);
                        continue; // Skip invalid entries but continue processing
                    }
                }
            },
            Err(e) => {
                eprintln!("Error reading line: {}", e);
                break; // Stop processing on IO error
            }
        }
    }

    Ok(())
}

fn parse_csv_line(line: &str) -> Result<StockEntry, Box<dyn Error>> {
    let fields: Vec<&str> = line.split(',').collect();

    if fields.len() < 3 {
        return Err("Insufficient fields in CSV line".into());
    }

    let symbol = fields[0].to_string();
    let timestamp = fields[1].to_string();
    let price = fields[2].parse::<f64>()?;

    Ok(StockEntry {
        symbol,
        timestamp,
        price,
    })
}

fn calculate_moving_average(entries: &VecDeque<StockEntry>) -> f64 {
    if entries.is_empty() {
        return 0.0;
    }

    let sum: f64 = entries.iter().map(|entry| entry.price).sum();
    sum / entries.len() as f64
}

