fn main() {
    // Create shared state protected by a mutex
    let state = Arc::new(Mutex::new(HashMap::<String, i64>::new()));

    // Bind to a specific port
    let listener = TcpListener::bind("127.0.0.1:8080").expect("Failed to bind to port");
    println!("Server listening on port 8080");

    // Accept connections and process them in separate threads
    for stream in listener.incoming() {
        match stream {
            Ok(stream) => {
                let state_clone = Arc::clone(&state);
                thread::spawn(move || {
                    handle_connection(stream, state_clone);
                });
            }
            Err(e) => {
                eprintln!("Connection failed: {}", e);
            }
        }
    }
}

fn handle_connection(mut stream: TcpStream, state: Arc<Mutex<HashMap<String, i64>>>) {
    let mut buffer = [0; 1024];

    // Read the request
    match stream.read(&mut buffer) {
        Ok(size) => {
            let request = String::from_utf8_lossy(&buffer[..size]);

            // Check if it's a POST request
            if request.starts_with("POST") {
                // Find the JSON payload
                if let Some(body_start) = request.find("\r\n\r\n") {
                    let body = &request[body_start + 4..];
                    process_json(body, state.clone());

                    // Send a success response
                    let response = "HTTP/1.1 200 OK\r\nContent-Type: text/plain\r\n\r\nSuccess";
                    let _ = stream.write_all(response.as_bytes());
                } else {
                    // Invalid request format
                    let response = "HTTP/1.1 400 Bad Request\r\nContent-Type: text/plain\r\n\r\nInvalid request format";
                    let _ = stream.write_all(response.as_bytes());
                }
            } else {
                // Not a POST request
                let response = "HTTP/1.1 405 Method Not Allowed\r\nContent-Type: text/plain\r\n\r\nOnly POST requests are supported";
                let _ = stream.write_all(response.as_bytes());
            }
        }
        Err(e) => {
            eprintln!("Failed to read from connection: {}", e);
        }
    }
}

fn process_json(json_str: &str, state: Arc<Mutex<HashMap<String, i64>>>) {
    // Try to parse the JSON manually since we're not using external crates
    let trimmed = json_str.trim();
    if !trimmed.starts_with('{') || !trimmed.ends_with('}') {
        eprintln!("Error parsing JSON: Not a valid JSON object");
        return;
    }

    let mut current_state = state.lock().unwrap();

    // Simple JSON parsing without external crates
    // Remove the outer braces
    let content = &trimmed[1..trimmed.len()-1].trim();

    // Split by commas (outside of quotes)
    let mut in_quotes = false;
    let mut segments = Vec::new();
    let mut start = 0;

    for (i, c) in content.char_indices() {
        if c == '"' {
            in_quotes = !in_quotes;
        } else if c == ',' && !in_quotes {
            segments.push(&content[start..i]);
            start = i + 1;
        }
    }

    // Add the last segment
    if start < content.len() {
        segments.push(&content[start..]);
    }

    // Process each key-value pair
    for segment in segments {
        let kv: Vec<&str> = segment.splitn(2, ':').collect();
        if kv.len() == 2 {
            let key = kv[0].trim();
            let value = kv[1].trim();

            // Extract the key (remove quotes)
            let key = if key.starts_with('"') && key.ends_with('"') {
                &key[1..key.len()-1]
            } else {
                eprintln!("Error: Invalid key format in JSON");
                continue;
            };

            // Parse the value as an integer
            let value_str = value.trim();
            if let Ok(value_int) = value_str.parse::<i64>() {
                *current_state.entry(key.to_string()).or_insert(0) += value_int;
            } else {
                eprintln!("Error: Value is not a valid integer");
                continue;
            }
        }
    }

    println!("Current state: {:?}", *current_state);
}

