package com.library.controller;

import com.library.dto.MediaDTO;
import com.library.service.MediaService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.concurrent.CompletableFuture;

@RestController
@RequestMapping("/api/media")
public class MediaController {

    private final MediaService mediaService;

    @Autowired
    public MediaController(MediaService mediaService) {
        this.mediaService = mediaService;
    }

    @GetMapping
    public CompletableFuture<ResponseEntity<List<MediaDTO>>> getAllMedia() {
        return mediaService.getAllMediaAsync()
            .thenApply(ResponseEntity::ok);
    }

    @GetMapping("/{id}")
    public CompletableFuture<ResponseEntity<MediaDTO>> getMediaById(@PathVariable Long id) {
        return mediaService.getMediaByIdAsync(id)
            .thenApply(optionalMedia -> 
                optionalMedia.map(ResponseEntity::ok)
                    .orElseGet(() -> ResponseEntity.notFound().build())
            );
    }

    @PostMapping
    public CompletableFuture<ResponseEntity<MediaDTO>> createMedia(@RequestBody MediaDTO mediaDTO) {
        return mediaService.createMediaAsync(mediaDTO)
            .thenApply(createdMedia -> 
                ResponseEntity.status(HttpStatus.CREATED).body(createdMedia)
            );
    }

    @PutMapping("/{id}")
    public CompletableFuture<ResponseEntity<MediaDTO>> updateMedia(
        @PathVariable Long id, 
        @RequestBody MediaDTO mediaDTO
    ) {
        return mediaService.updateMediaAsync(id, mediaDTO)
            .thenApply(ResponseEntity::ok)
            .exceptionally(ex -> ResponseEntity.notFound().build());
    }

    @DeleteMapping("/{id}")
    public CompletableFuture<ResponseEntity<Void>> deleteMedia(@PathVariable Long id) {
        return mediaService.deleteMediaAsync(id)
            .thenApply(v -> ResponseEntity.noContent().<Void>build())
            .exceptionally(ex -> ResponseEntity.notFound().build());
    }
}

