package com.library.repository;

import com.library.model.Book;
import com.library.model.Journal;
import com.library.model.Magazine;
import com.library.model.Media;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.jdbc.support.GeneratedKeyHolder;
import org.springframework.jdbc.support.KeyHolder;
import org.springframework.stereotype.Repository;
import org.springframework.transaction.annotation.Transactional;

import java.sql.PreparedStatement;
import java.sql.Statement;
import java.time.LocalDate;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

@Repository
public class MediaRepository {

    private final JdbcTemplate jdbcTemplate;

    @Autowired
    public MediaRepository(JdbcTemplate jdbcTemplate) {
        this.jdbcTemplate = jdbcTemplate;
    }

    @Transactional
    public Media save(Media media) {
        // First save common fields to media table
        KeyHolder keyHolder = new GeneratedKeyHolder();

        jdbcTemplate.update(connection -> {
            PreparedStatement ps = connection.prepareStatement(
                "INSERT INTO media (title, publisher, publish_date, isbn, media_type) VALUES (?, ?, ?, ?, ?)",
                Statement.RETURN_GENERATED_KEYS
            );
            ps.setString(1, media.getTitle());
            ps.setString(2, media.getPublisher());
            ps.setObject(3, media.getPublishDate());
            ps.setString(4, media.getIsbn());

            // Determine media type
            String mediaType;
            if (media instanceof Book) {
                mediaType = "BOOK";
            } else if (media instanceof Journal) {
                mediaType = "JOURNAL";
            } else if (media instanceof Magazine) {
                mediaType = "MAGAZINE";
            } else {
                mediaType = "UNKNOWN";
            }

            ps.setString(5, mediaType);
            return ps;
        }, keyHolder);

        Long id = keyHolder.getKey().longValue();
        media.setId(id);

        // Now handle specific media type details
        if (media instanceof Book book) {
            jdbcTemplate.update(
                "INSERT INTO book (media_id, author, page_count) VALUES (?, ?, ?)",
                id, book.getAuthor(), book.getPageCount()
            );

            // Handle genres (many-to-many relationship)
            if (book.getGenres() != null && !book.getGenres().isEmpty()) {
                for (String genre : book.getGenres()) {
                    // First ensure the genre exists
                    jdbcTemplate.update(
                        "INSERT INTO genre (name) VALUES (?) ON CONFLICT (name) DO NOTHING",
                        genre
                    );

                    // Now create the relationship
                    jdbcTemplate.update(
                        "INSERT INTO book_genre (book_id, genre_name) VALUES (?, ?)",
                        id, genre
                    );
                }
            }
        } else if (media instanceof Journal journal) {
            jdbcTemplate.update(
                "INSERT INTO journal (media_id, academic_field, peer_reviewed, volume, issue) VALUES (?, ?, ?, ?, ?)",
                id, journal.getAcademicField(), journal.isPeerReviewed(), journal.getVolume(), journal.getIssue()
            );
        } else if (media instanceof Magazine magazine) {
            jdbcTemplate.update(
                "INSERT INTO magazine (media_id, category, monthly, target_audience) VALUES (?, ?, ?, ?)",
                id, magazine.getCategory(), magazine.isMonthly(), magazine.getTargetAudience()
            );
        }

        return media;
    }

    @Transactional
    public void update(Media media) {
        // Update common fields in media table
        jdbcTemplate.update(
            "UPDATE media SET title = ?, publisher = ?, publish_date = ?, isbn = ? WHERE id = ?",
            media.getTitle(), media.getPublisher(), media.getPublishDate(), media.getIsbn(), media.getId()
        );

        // Update specific media type fields
        if (media instanceof Book book) {
            jdbcTemplate.update(
                "UPDATE book SET author = ?, page_count = ? WHERE media_id = ?",
                book.getAuthor(), book.getPageCount(), book.getId()
            );

            // Handle genres - first delete existing relationships
            jdbcTemplate.update("DELETE FROM book_genre WHERE book_id = ?", book.getId());

            // Then add new relationships
            if (book.getGenres() != null && !book.getGenres().isEmpty()) {
                for (String genre : book.getGenres()) {
                    // Ensure genre exists
                    jdbcTemplate.update(
                        "INSERT INTO genre (name) VALUES (?) ON CONFLICT (name) DO NOTHING",
                        genre
                    );

                    // Create the relationship
                    jdbcTemplate.update(
                        "INSERT INTO book_genre (book_id, genre_name) VALUES (?, ?)",
                        book.getId(), genre
                    );
                }
            }
        } else if (media instanceof Journal journal) {
            jdbcTemplate.update(
                "UPDATE journal SET academic_field = ?, peer_reviewed = ?, volume = ?, issue = ? WHERE media_id = ?",
                journal.getAcademicField(), journal.isPeerReviewed(), journal.getVolume(), journal.getIssue(), journal.getId()
            );
        } else if (media instanceof Magazine magazine) {
            jdbcTemplate.update(
                "UPDATE magazine SET category = ?, monthly = ?, target_audience = ? WHERE media_id = ?",
                magazine.getCategory(), magazine.isMonthly(), magazine.getTargetAudience(), magazine.getId()
            );
        }
    }

    @Transactional
    public void deleteById(Long id) {
        // First determine the media type
        String mediaType = jdbcTemplate.queryForObject(
            "SELECT media_type FROM media WHERE id = ?", 
            String.class, 
            id
        );

        // Delete specific media type data first
        switch (mediaType) {
            case "BOOK":
                jdbcTemplate.update("DELETE FROM book_genre WHERE book_id = ?", id);
                jdbcTemplate.update("DELETE FROM book WHERE media_id = ?", id);
                break;
            case "JOURNAL":
                jdbcTemplate.update("DELETE FROM journal WHERE media_id = ?", id);
                break;
            case "MAGAZINE":
                jdbcTemplate.update("DELETE FROM magazine WHERE media_id = ?", id);
                break;
        }

        // Then delete from the main media table
        jdbcTemplate.update("DELETE FROM media WHERE id = ?", id);
    }

    public Optional<Media> findById(Long id) {
        try {
            // First get the media type
            String mediaType = jdbcTemplate.queryForObject(
                "SELECT media_type FROM media WHERE id = ?", 
                String.class, 
                id
            );

            Media media = null;
            switch (mediaType) {
                case "BOOK":
                    media = findBookById(id);
                    break;
                case "JOURNAL":
                    media = findJournalById(id);
                    break;
                case "MAGAZINE":
                    media = findMagazineById(id);
                    break;
            }

            return Optional.ofNullable(media);
        } catch (Exception e) {
            return Optional.empty();
        }
    }

    private Book findBookById(Long id) {
        // Join media and book tables
        Book book = jdbcTemplate.queryForObject(
            """
            SELECT m.id, m.title, m.publisher, m.publish_date, m.isbn, b.author, b.page_count
            FROM media m
            JOIN book b ON m.id = b.media_id
            WHERE m.id = ?
            """,
            (rs, rowNum) -> {
                Book b = new Book();
                b.setId(rs.getLong("id"));
                b.setTitle(rs.getString("title"));
                b.setPublisher(rs.getString("publisher"));
                b.setPublishDate(rs.getObject("publish_date", LocalDate.class));
                b.setIsbn(rs.getString("isbn"));
                b.setAuthor(rs.getString("author"));
                b.setPageCount(rs.getInt("page_count"));
                return b;
            },
            id
        );

        // Get genres
        List<String> genres = jdbcTemplate.queryForList(
            "SELECT genre_name FROM book_genre WHERE book_id = ?",
            String.class,
            id
        );

        book.setGenres(genres);
        return book;
    }

    private Journal findJournalById(Long id) {
        return jdbcTemplate.queryForObject(
            """
            SELECT m.id, m.title, m.publisher, m.publish_date, m.isbn, 
                   j.academic_field, j.peer_reviewed, j.volume, j.issue
            FROM media m
            JOIN journal j ON m.id = j.media_id
            WHERE m.id = ?
            """,
            (rs, rowNum) -> {
                Journal j = new Journal();
                j.setId(rs.getLong("id"));
                j.setTitle(rs.getString("title"));
                j.setPublisher(rs.getString("publisher"));
                j.setPublishDate(rs.getObject("publish_date", LocalDate.class));
                j.setIsbn(rs.getString("isbn"));
                j.setAcademicField(rs.getString("academic_field"));
                j.setPeerReviewed(rs.getBoolean("peer_reviewed"));
                j.setVolume(rs.getInt("volume"));
                j.setIssue(rs.getInt("issue"));
                return j;
            },
            id
        );
    }

    private Magazine findMagazineById(Long id) {
        return jdbcTemplate.queryForObject(
            """
            SELECT m.id, m.title, m.publisher, m.publish_date, m.isbn, 
                   mag.category, mag.monthly, mag.target_audience
            FROM media m
            JOIN magazine mag ON m.id = mag.media_id
            WHERE m.id = ?
            """,
            (rs, rowNum) -> {
                Magazine mag = new Magazine();
                mag.setId(rs.getLong("id"));
                mag.setTitle(rs.getString("title"));
                mag.setPublisher(rs.getString("publisher"));
                mag.setPublishDate(rs.getObject("publish_date", LocalDate.class));
                mag.setIsbn(rs.getString("isbn"));
                mag.setCategory(rs.getString("category"));
                mag.setMonthly(rs.getBoolean("monthly"));
                mag.setTargetAudience(rs.getString("target_audience"));
                return mag;
            },
            id
        );
    }

    public List<Media> findAll() {
        // Get all media IDs with their types
        List<Object[]> mediaIds = jdbcTemplate.query(
            "SELECT id, media_type FROM media",
            (rs, rowNum) -> new Object[] {
                rs.getLong("id"),
                rs.getString("media_type")
            }
        );

        // For each ID, load the full media object
        return mediaIds.stream()
            .map(row -> {
                Long id = (Long) row[0];
                String type = (String) row[1];

                Media media = null;
                switch (type) {
                    case "BOOK":
                        media = findBookById(id);
                        break;
                    case "JOURNAL":
                        media = findJournalById(id);
                        break;
                    case "MAGAZINE":
                        media = findMagazineById(id);
                        break;
                }

                return media;
            })
            .collect(Collectors.toList());
    }
}

