package com.library.service;

import com.library.dto.MediaDTO;
import com.library.model.Book;
import com.library.model.Journal;
import com.library.model.Magazine;
import com.library.model.Media;
import com.library.repository.MediaRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.Optional;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.Executor;
import java.util.stream.Collectors;

@Service
public class MediaService {

    private final MediaRepository mediaRepository;
    private final Executor virtualThreadExecutor;

    @Autowired
    public MediaService(MediaRepository mediaRepository, Executor virtualThreadExecutor) {
        this.mediaRepository = mediaRepository;
        this.virtualThreadExecutor = virtualThreadExecutor;
    }

    @Transactional(readOnly = true)
    public CompletableFuture<List<MediaDTO>> getAllMediaAsync() {
        return CompletableFuture.supplyAsync(() -> 
            mediaRepository.findAll().stream()
                .map(this::convertToDTO)
                .collect(Collectors.toList()),
            virtualThreadExecutor
        );
    }

    @Transactional(readOnly = true)
    public CompletableFuture<Optional<MediaDTO>> getMediaByIdAsync(Long id) {
        return CompletableFuture.supplyAsync(() -> 
            mediaRepository.findById(id)
                .map(this::convertToDTO),
            virtualThreadExecutor
        );
    }

    @Transactional
    public CompletableFuture<MediaDTO> createMediaAsync(MediaDTO mediaDTO) {
        return CompletableFuture.supplyAsync(() -> {
            Media media = convertToEntity(mediaDTO);
            Media savedMedia = mediaRepository.save(media);
            return convertToDTO(savedMedia);
        }, virtualThreadExecutor);
    }

    @Transactional
    public CompletableFuture<MediaDTO> updateMediaAsync(Long id, MediaDTO mediaDTO) {
        return CompletableFuture.supplyAsync(() -> {
            Optional<Media> existingMedia = mediaRepository.findById(id);

            if (existingMedia.isPresent()) {
                Media media = convertToEntity(mediaDTO);
                media.setId(id);
                mediaRepository.update(media);
                return convertToDTO(media);
            } else {
                throw new RuntimeException("Media not found with id: " + id);
            }
        }, virtualThreadExecutor);
    }

    @Transactional
    public CompletableFuture<Void> deleteMediaAsync(Long id) {
        return CompletableFuture.runAsync(() -> {
            mediaRepository.deleteById(id);
        }, virtualThreadExecutor);
    }

    private MediaDTO convertToDTO(Media media) {
        if (media instanceof Book book) {
            return new MediaDTO(
                book.getId(),
                "BOOK",
                book.getTitle(),
                book.getPublisher(),
                book.getPublishDate(),
                book.getIsbn(),
                book.getAuthor(),
                book.getPageCount(),
                book.getGenres() != null ? book.getGenres().toArray(new String[0]) : null,
                null, null, null, null,
                null, null, null
            );
        } else if (media instanceof Journal journal) {
            return new MediaDTO(
                journal.getId(),
                "JOURNAL",
                journal.getTitle(),
                journal.getPublisher(),
                journal.getPublishDate(),
                journal.getIsbn(),
                null, null, null,
                journal.getAcademicField(),
                journal.isPeerReviewed(),
                journal.getVolume(),
                journal.getIssue(),
                null, null, null
            );
        } else if (media instanceof Magazine magazine) {
            return new MediaDTO(
                magazine.getId(),
                "MAGAZINE",
                magazine.getTitle(),
                magazine.getPublisher(),
                magazine.getPublishDate(),
                magazine.getIsbn(),
                null, null, null,
                null, null, null, null,
                magazine.getCategory(),
                magazine.isMonthly(),
                magazine.getTargetAudience()
            );
        } else {
            throw new IllegalArgumentException("Unknown media type");
        }
    }

    private Media convertToEntity(MediaDTO dto) {
        switch (dto.type()) {
            case "BOOK" -> {
                Book book = new Book();
                book.setId(dto.id());
                book.setTitle(dto.title());
                book.setPublisher(dto.publisher());
                book.setPublishDate(dto.publishDate());
                book.setIsbn(dto.isbn());
                book.setAuthor(dto.author());
                book.setPageCount(dto.pageCount() != null ? dto.pageCount() : 0);
                book.setGenres(dto.genres() != null ? List.of(dto.genres()) : List.of());
                return book;
            }
            case "JOURNAL" -> {
                Journal journal = new Journal();
                journal.setId(dto.id());
                journal.setTitle(dto.title());
                journal.setPublisher(dto.publisher());
                journal.setPublishDate(dto.publishDate());
                journal.setIsbn(dto.isbn());
                journal.setAcademicField(dto.academicField());
                journal.setPeerReviewed(dto.peerReviewed() != null ? dto.peerReviewed() : false);
                journal.setVolume(dto.volume() != null ? dto.volume() : 0);
                journal.setIssue(dto.issue() != null ? dto.issue() : 0);
                return journal;
            }
            case "MAGAZINE" -> {
                Magazine magazine = new Magazine();
                magazine.setId(dto.id());
                magazine.setTitle(dto.title());
                magazine.setPublisher(dto.publisher());
                magazine.setPublishDate(dto.publishDate());
                magazine.setIsbn(dto.isbn());
                magazine.setCategory(dto.category());
                magazine.setMonthly(dto.monthly() != null ? dto.monthly() : false);
                magazine.setTargetAudience(dto.targetAudience());
                return magazine;
            }
            default -> throw new IllegalArgumentException("Unknown media type: " + dto.type());
        }
    }
}

