package com.library.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.jdbc.datasource.DataSourceTransactionManager;
import org.springframework.transaction.PlatformTransactionManager;
import org.springframework.transaction.annotation.EnableTransactionManagement;

import javax.sql.DataSource;

@Configuration
@EnableTransactionManagement
public class DatabaseConfig {

    @Bean
    public PlatformTransactionManager transactionManager(DataSource dataSource) {
        return new DataSourceTransactionManager(dataSource);
    }

    @Bean
    public JdbcTemplate jdbcTemplate(DataSource dataSource) {
        JdbcTemplate jdbcTemplate = new JdbcTemplate(dataSource);

        // Create the tables if they don't exist
        jdbcTemplate.execute("""
            CREATE TABLE IF NOT EXISTS media (
                id BIGINT AUTO_INCREMENT PRIMARY KEY,
                title VARCHAR(255) NOT NULL,
                publisher VARCHAR(255),
                publish_date DATE,
                isbn VARCHAR(50),
                media_type VARCHAR(20) NOT NULL
            )
        """);

        jdbcTemplate.execute("""
            CREATE TABLE IF NOT EXISTS book (
                media_id BIGINT PRIMARY KEY,
                author VARCHAR(255),
                page_count INT,
                FOREIGN KEY (media_id) REFERENCES media(id) ON DELETE CASCADE
            )
        """);

        jdbcTemplate.execute("""
            CREATE TABLE IF NOT EXISTS genre (
                name VARCHAR(100) PRIMARY KEY
            )
        """);

        jdbcTemplate.execute("""
            CREATE TABLE IF NOT EXISTS book_genre (
                book_id BIGINT,
                genre_name VARCHAR(100),
                PRIMARY KEY (book_id, genre_name),
                FOREIGN KEY (book_id) REFERENCES book(media_id) ON DELETE CASCADE,
                FOREIGN KEY (genre_name) REFERENCES genre(name) ON DELETE CASCADE
            )
        """);

        jdbcTemplate.execute("""
            CREATE TABLE IF NOT EXISTS journal (
                media_id BIGINT PRIMARY KEY,
                academic_field VARCHAR(100),
                peer_reviewed BOOLEAN DEFAULT FALSE,
                volume INT,
                issue INT,
                FOREIGN KEY (media_id) REFERENCES media(id) ON DELETE CASCADE
            )
        """);

        jdbcTemplate.execute("""
            CREATE TABLE IF NOT EXISTS magazine (
                media_id BIGINT PRIMARY KEY,
                category VARCHAR(100),
                monthly BOOLEAN DEFAULT FALSE,
                target_audience VARCHAR(100),
                FOREIGN KEY (media_id) REFERENCES media(id) ON DELETE CASCADE
            )
        """);

        return jdbcTemplate;
    }
}

