#!/usr/bin/env python3
import os
import time
import json
import logging
import hashlib
import base64
from typing import Dict, Any, Optional, TypedDict, NotRequired
from pathlib import Path
from datetime import datetime
from cryptography.fernet import Fernet
import pymongo
from pymongo.collection import Collection
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler, FileCreatedEvent, FileModifiedEvent

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s - %(levelname)s - %(message)s",
    handlers=[
        logging.FileHandler("directory_monitor.log"),
        logging.StreamHandler()
    ]
)
logger = logging.getLogger(__name__)

# TypedDict for JSON structure validation
class JsonData(TypedDict):
    id: str
    name: str
    timestamp: str
    data: Dict[str, Any]
    tags: list[str]
    status: NotRequired[str]

class EncryptionHandler:
    def __init__(self, key_file: str = "encryption.key"):
        self.key_file = key_file
        self.key = self._load_or_generate_key()
        self.fernet = Fernet(self.key)

    def _load_or_generate_key(self) -> bytes:
        try:
            if os.path.exists(self.key_file):
                with open(self.key_file, "rb") as f:
                    return f.read()
            else:
                key = Fernet.generate_key()
                with open(self.key_file, "wb") as f:
                    f.write(key)
                os.chmod(self.key_file, 0o600)  # Restrict permissions
                return key
        except Exception as e:
            logger.error(f"Error handling encryption key: {e}")
            raise

    def encrypt(self, data: str) -> bytes:
        return self.fernet.encrypt(data.encode())

    def decrypt(self, data: bytes) -> str:
        return self.fernet.decrypt(data).decode()

class MongoDBHandler:
    def __init__(self, connection_string: str, db_name: str, collection_name: str):
        self.encryption = EncryptionHandler()
        self.client = pymongo.MongoClient(connection_string)
        self.db = self.client[db_name]
        self.collection = self.db[collection_name]
        logger.info(f"Connected to MongoDB: {db_name}.{collection_name}")

    def update_document(self, document: Dict[str, Any]) -> None:
        try:
            # Encrypt sensitive fields
            if "data" in document:
                document["data"] = self._encrypt_dict(document["data"])

            # Use upsert to insert if not exists, update if exists
            result = self.collection.update_one(
                {"id": document["id"]},
                {"$set": document},
                upsert=True
            )

            if result.upserted_id:
                logger.info(f"Inserted new document with ID: {document['id']}")
            else:
                logger.info(f"Updated document with ID: {document['id']}")

        except Exception as e:
            logger.error(f"Error updating MongoDB: {e}")
            raise

    def _encrypt_dict(self, data: Dict[str, Any]) -> Dict[str, Any]:
        encrypted_data = {}
        for key, value in data.items():
            if isinstance(value, dict):
                encrypted_data[key] = self._encrypt_dict(value)
            elif isinstance(value, str):
                encrypted_value = self.encryption.encrypt(value)
                encrypted_data[key] = base64.b64encode(encrypted_value).decode()
            else:
                encrypted_data[key] = value
        return encrypted_data

class JsonFileHandler(FileSystemEventHandler):
    def __init__(self, mongo_handler: MongoDBHandler):
        self.mongo_handler = mongo_handler
        self.processed_files = {}

    def on_created(self, event: FileCreatedEvent) -> None:
        if event.is_directory or not event.src_path.endswith(".json"):
            return
        self._process_file(event.src_path)

    def on_modified(self, event: FileModifiedEvent) -> None:
        if event.is_directory or not event.src_path.endswith(".json"):
            return
        self._process_file(event.src_path)

    def _process_file(self, file_path: str) -> None:
        try:
            # Check if file was recently processed (to avoid duplicate processing)
            file_stat = os.stat(file_path)
            last_modified = file_stat.st_mtime

            if file_path in self.processed_files and self.processed_files[file_path] == last_modified:
                return

            self.processed_files[file_path] = last_modified
            logger.info(f"Processing file: {file_path}")

            with open(file_path, 'r') as f:
                json_data = json.load(f)

            # Validate JSON structure using Python 3.13 pattern matching
            match json_data:
                case {"id": str(id), "name": str(name), "timestamp": str(timestamp), 
                      "data": dict(data), "tags": list(tags), **rest} if self._validate_json(json_data):
                    logger.info(f"Valid JSON structure found in {file_path}")
                    self.mongo_handler.update_document(json_data)
                case _:
                    logger.error(f"Invalid JSON structure in {file_path}")

        except json.JSONDecodeError as e:
            logger.error(f"JSON parsing error in {file_path}: {e}")
        except Exception as e:
            logger.error(f"Error processing file {file_path}: {e}")

    def _validate_json(self, data: Dict[str, Any]) -> bool:
        try:
            # Additional validation beyond structure
            if not data["id"] or not isinstance(data["id"], str):
                return False

            # Validate timestamp format
            try:
                datetime.fromisoformat(data["timestamp"])
            except ValueError:
                return False

            # Check if tags are all strings
            if not all(isinstance(tag, str) for tag in data["tags"]):
                return False

            return True
        except Exception as e:
            logger.error(f"Validation error: {e}")
            return False

def main():
    # Configuration
    WATCH_DIRECTORY = os.environ.get("WATCH_DIRECTORY", "./data")
    MONGO_CONNECTION = os.environ.get("MONGO_CONNECTION", "mongodb://localhost:27017/")
    MONGO_DB = os.environ.get("MONGO_DB", "file_monitor")
    MONGO_COLLECTION = os.environ.get("MONGO_COLLECTION", "json_data")

    # Ensure watch directory exists
    Path(WATCH_DIRECTORY).mkdir(parents=True, exist_ok=True)

    try:
        # Initialize MongoDB handler
        mongo_handler = MongoDBHandler(MONGO_CONNECTION, MONGO_DB, MONGO_COLLECTION)

        # Set up file system observer
        event_handler = JsonFileHandler(mongo_handler)
        observer = Observer()
        observer.schedule(event_handler, WATCH_DIRECTORY, recursive=True)
        observer.start()

        logger.info(f"Started monitoring directory: {WATCH_DIRECTORY}")

        # Process existing files
        for file_path in Path(WATCH_DIRECTORY).glob("**/*.json"):
            event_handler._process_file(str(file_path))

        # Keep the script running
        try:
            while True:
                time.sleep(1)
        except KeyboardInterrupt:
            observer.stop()
            logger.info("Monitoring stopped")

        observer.join()

    except Exception as e:
        logger.critical(f"Fatal error: {e}")
        return 1

    return 0

if __name__ == "__main__":
    exit(main())

