        System.out.println("Config file monitoring started. Watching for changes...");

        try {
            while (true) {
                WatchKey key;
                try {
                    key = watchService.poll(10, TimeUnit.SECONDS);
                    if (key == null) {
                        continue;
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    break;
                }

                Path dir = watchKeys.get(key);
                if (dir == null) {
                    System.err.println("WatchKey not recognized!");
                    continue;
                }

                for (WatchEvent<?> event : key.pollEvents()) {
                    WatchEvent.Kind<?> kind = event.kind();

                    if (kind == StandardWatchEventKinds.OVERFLOW) {
                        continue;
                    }

                    @SuppressWarnings("unchecked")
                    WatchEvent<Path> ev = (WatchEvent<Path>) event;
                    Path filename = ev.context();
                    Path fullPath = dir.resolve(filename);

                    if (isConfigFile(fullPath)) {
                        String eventType = getEventType(kind);
                        String details = getFileDetails(fullPath, kind);
                        logEvent(eventType, fullPath.toString(), details);
                    }
                }

                boolean valid = key.reset();
                if (!valid) {
                    watchKeys.remove(key);
                    if (watchKeys.isEmpty()) {
                        break;
                    }
                }
            }
        } catch (IOException e) {
            System.err.println("Error during file monitoring: " + e.getMessage());
        } finally {
            try {
                watchService.close();
            } catch (IOException e) {
                System.err.println("Error closing watch service: " + e.getMessage());
            }
        }
    }

