        if (!Files.exists(path)) {
            return true;
        }

        String fileName = path.getFileName().toString().toLowerCase();
        String[] configExtensions = {".properties", ".xml", ".json", ".yaml", ".yml", ".conf", ".cfg", ".ini", ".config", ".txt"};

        for (String ext : configExtensions) {
            if (fileName.endsWith(ext)) {
                return true;
            }
        }

        return false;
    }

    private String getEventType(WatchEvent.Kind<?> kind) {
        if (kind == StandardWatchEventKinds.ENTRY_CREATE) {
            return "CREATE";
        } else if (kind == StandardWatchEventKinds.ENTRY_DELETE) {
            return "DELETE";
        } else if (kind == StandardWatchEventKinds.ENTRY_MODIFY) {
            return "MODIFY";
        } else {
            return "UNKNOWN";
        }
    }

    private String getFileDetails(Path path, WatchEvent.Kind<?> kind) {
        if (kind == StandardWatchEventKinds.ENTRY_DELETE) {
            return "File was deleted";
        }

        try {
            BasicFileAttributes attrs = Files.readAttributes(path, BasicFileAttributes.class);
            return String.format("Size: %d bytes, Last modified: %s, Creation time: %s",
                    attrs.size(),
                    attrs.lastModifiedTime(),
                    attrs.creationTime());
        } catch (IOException e) {
            return "Unable to read file attributes";
        }
    }

    private void logEvent(String eventType, String filePath, String details) throws IOException {
        String jsonLog = String.format(
            "{\n" +
            "  \"timestamp\": \"%s\",\n" +
            "  \"eventType\": \"%s\",\n" +
            "  \"filePath\": \"%s\",\n" +
            "  \"details\": \"%s\"\n" +
            "}\n",
            LocalDateTime.now().format(formatter),
            eventType,
            filePath.replace("\\", "\\\\"),
            details.replace("\"", "\\\"")
        );

        Files.writeString(
            logFilePath, 
            jsonLog, 
            StandardOpenOption.CREATE, 
            StandardOpenOption.APPEND
        );

        System.out.println(jsonLog);
    }

