            socket.write_all(json.as_bytes()).await?;
            return Err(Box::new(std::io::Error::new(std::io::ErrorKind::InvalidData, e)));
        }
    };

    info!("Received request from {}: {:?}", addr, request);

    // Process the data
    let result = process_data(&request.data, &request.operation);

    // Prepare and send response
    let response = Response {
        result,
        status: "success".to_string(),
