import java.net.InetSocketAddress;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.StandardCopyOption;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.Executors;

import com.fasterxml.jackson.databind.ObjectMapper;

public class DocumentPreviewService {

    private final ObjectMapper objectMapper = new ObjectMapper();
    private final int PORT = 8080;

    public void startServer() throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(PORT), 0);
        server.createContext("/api/preview", new PreviewHandler());
        server.setExecutor(Executors.newFixedThreadPool(10));
        server.start();
        System.out.println("Server started on port " + PORT);
    }

    class PreviewHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if ("POST".equals(exchange.getRequestMethod())) {
                try {
                    Path tempFile = Files.createTempFile("upload-", "");
                    try (InputStream is = exchange.getRequestBody()) {
                        Files.copy(is, tempFile, StandardCopyOption.REPLACE_EXISTING);
                    }

                    DocumentSummary summary = generateSummary(tempFile.toFile());

                    byte[] response = objectMapper.writeValueAsBytes(summary);
                    exchange.getResponseHeaders().set("Content-Type", "application/json");
                    exchange.sendResponseHeaders(200, response.length);

                    try (OutputStream os = exchange.getResponseBody()) {
                        os.write(response);
                    }

                    Files.deleteIfExists(tempFile);
                } catch (Exception e) {
                    String errorResponse = "{\"error\":\"" + e.getMessage() + "\"}";
                    exchange.getResponseHeaders().set("Content-Type", "application/json");
                    exchange.sendResponseHeaders(500, errorResponse.getBytes().length);
                    try (OutputStream os = exchange.getResponseBody()) {
                        os.write(errorResponse.getBytes());
                    }
                }
            } else {
                String message = "Method not allowed";
                exchange.sendResponseHeaders(405, message.getBytes().length);
                try (OutputStream os = exchange.getResponseBody()) {
                    os.write(message.getBytes());
                }
            }
        }
    }

    public DocumentSummary generateSummary(File file) throws IOException {
        String extension = getFileExtension(file.getName());
        String content = extractContent(file, extension);

        DocumentSummary summary = new DocumentSummary();
        summary.setFileName(file.getName());
        summary.setFileType(extension.toUpperCase());
        summary.setWordCount(countWords(content));
        summary.setCharacterCount(content.length());
        summary.setDetectedLanguage(detectLanguage(content));
        summary.setSummary(generateTextSummary(content));

        return summary;
    }

    private String extractContent(File file, String extension) throws IOException {
        switch (extension.toLowerCase()) {
            case "pdf":
                return extractPdfContent(file);
            case "docx":
                return extractDocxContent(file);
            case "txt":
                return extractTxtContent(file);
            default:
                throw new UnsupportedOperationException("Unsupported file type: " + extension);
        }
    }

    private String extractPdfContent(File file) throws IOException {
        try (PDDocument document = PDDocument.load(file)) {
            PDFTextStripper stripper = new PDFTextStripper();
            return stripper.getText(document);
        }
    }

    private String extractDocxContent(File file) throws IOException {
        try (XWPFDocument document = new XWPFDocument(Files.newInputStream(file.toPath()))) {
            XWPFWordExtractor extractor = new XWPFWordExtractor(document);
            return extractor.getText();
        }
    }

    private String extractTxtContent(File file) throws IOException {
        return Files.readString(file.toPath(), StandardCharsets.UTF_8);
    }

    private int countWords(String content) {
        if (content == null || content.isEmpty()) {
            return 0;
        }
        return content.split("\\s+").length;
    }

    private String detectLanguage(String content) {
        if (content == null || content.length() < 10) {
            return "Unknown";
        }

        Map<String, String> languagePatterns = new HashMap<>();
        languagePatterns.put("en", "the and that have with");
        languagePatterns.put("es", "el la que los del");
        languagePatterns.put("fr", "le la les des que");
        languagePatterns.put("de", "der die das und zu");

        String contentLower = content.toLowerCase();
        String detectedLanguage = "Unknown";
        int highestMatches = 0;

        for (Map.Entry<String, String> entry : languagePatterns.entrySet()) {
            String[] patterns = entry.getValue().split(" ");
            int matches = 0;

            for (String pattern : patterns) {
                if (contentLower.contains(pattern)) {
                    matches++;
                }
            }

            if (matches > highestMatches) {
                highestMatches = matches;
                detectedLanguage = entry.getKey();
            }
        }

        return detectedLanguage;
    }

    private String generateTextSummary(String content) {
        if (content == null) {
            return "";
        }

        int summaryLength = Math.min(content.length(), 200);
        String summary = content.substring(0, summaryLength);

        if (summaryLength < content.length()) {
            summary += "...";
        }

        return summary;
    }

    private String getFileExtension(String fileName) {
        int dotIndex = fileName.lastIndexOf('.');
        if (dotIndex > 0 && dotIndex < fileName.length() - 1) {
            return fileName.substring(dotIndex + 1);
        }
        return "";
    }

    public static void main(String[] args) {
        try {
            new DocumentPreviewService().startServer();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

class DocumentSummary {
    private String fileName;
    private String fileType;
    private int wordCount;
    private int characterCount;
    private String detectedLanguage;
    private String summary;

    public DocumentSummary() {
    }

    public String getFileName() {
        return fileName;
    }

    public void setFileName(String fileName) {
        this.fileName = fileName;
    }

    public String getFileType() {
        return fileType;
    }

    public void setFileType(String fileType) {
        this.fileType = fileType;
    }

    public int getWordCount() {
        return wordCount;
    }

    public void setWordCount(int wordCount) {
        this.wordCount = wordCount;
    }

    public int getCharacterCount() {
        return characterCount;
    }

    public void setCharacterCount(int characterCount) {
        this.characterCount = characterCount;
    }

    public String getDetectedLanguage() {
        return detectedLanguage;
    }

    public void setDetectedLanguage(String detectedLanguage) {
        this.detectedLanguage = detectedLanguage;
    }

    public String getSummary() {
        return summary;
    }

    public void setSummary(String summary) {
        this.summary = summary;
    }
}
